function getText() {
  if (message && message.contact && message.contact.phone_number) {
    return String(message.contact.phone_number);
  }
  if (message && message.text) {
    return String(message.text).trim();
  }
  return "";
}

function cleanupInternal() {
  delete_context("_booking_step");
}

function ask(prompt) {
  send_message({ text: prompt, parse_mode: "HTML" });
}

var steps = [
  {
    key: "booking_name",
    prompt: get_context("param_name_prompt") || "Bron qilish uchun ism va familiyangizni kiriting:",
    error: "Iltimos, to'liq ism kiriting.",
    validate: function(value) { return value.length >= 3; }
  },
  {
    key: "booking_service",
    prompt: get_context("param_service_prompt") || "Qaysi xizmat, mutaxassis yoki yo'nalishga yozilmoqchisiz?",
    error: "Xizmat nomini kiriting.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "booking_date",
    prompt: get_context("param_date_prompt") || "Qulay sana va vaqtni yozing. Masalan: 25-aprel, 18:00",
    error: "Iltimos, sana yoki vaqtni kiriting.",
    validate: function(value) { return value.length >= 3; }
  },
  {
    key: "booking_phone",
    prompt: get_context("param_phone_prompt") || "Bog'lanish uchun telefon raqamingizni yuboring:",
    error: "Telefon raqamini +998901234567 formatida kiriting yoki kontakt yuboring.",
    validate: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      return /^\+?\d{9,15}$/.test(cleaned);
    },
    normalize: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      if (cleaned[0] !== "+") return "+" + cleaned;
      return cleaned;
    }
  },
  {
    key: "booking_comment",
    prompt: get_context("param_comment_prompt") || "Qo'shimcha izoh bo'lsa yozing. Bo'lmasa '-' deb yuboring.",
    error: "Javobni qayta yuboring.",
    validate: function(value) { return value.length >= 1; },
    normalize: function(value) {
      if (value === "-") return "";
      return value;
    }
  }
];

var step = parseInt(get_context("_booking_step") || "0", 10);
var answer = getText();

if (answer.toLowerCase() === "/cancel") {
  cleanupInternal();
  exit("cancelled");
}

if (step > 0) {
  var previous = steps[step - 1];
  var value = answer;
  if (previous.normalize) value = previous.normalize(value);
  if (!previous.validate(value)) {
    ask(previous.error + "\n\nBekor qilish uchun /cancel yuboring.");
    wait_for_input();
  }
  set_context(previous.key, value);
}

if (step >= steps.length) {
  var successMessage = get_context("param_success_message") || (
    "<b>Bron so'rovi qabul qilindi.</b>\n\n" +
    "👤 Mijoz: " + (get_context("booking_name") || "") + "\n" +
    "🧩 Xizmat: " + (get_context("booking_service") || "") + "\n" +
    "📅 Vaqt: " + (get_context("booking_date") || "") + "\n" +
    "📞 Telefon: " + (get_context("booking_phone") || "") + "\n" +
    "📝 Izoh: " + (get_context("booking_comment") || "-")
  );
  send_message({ text: successMessage, parse_mode: "HTML" });
  cleanupInternal();
  exit("completed");
}

ask(steps[step].prompt + "\n\nBekor qilish uchun /cancel yuboring.");
set_context("_booking_step", String(step + 1));
wait_for_input();
